        $users = New-MockUsers -Seed 42 -Count 0
        $users.Count | Should -Be 0
    }

    It 'Should handle zero count for products' {
        $products = New-MockProducts -Seed 42 -Count 0
        $products.Count | Should -Be 0
    }
}

